struct AgentResult {
    bool success;
    std::string message;
    std::string payload;
    double durationMs;
};

// ============================================================================
// State Machine
// ============================================================================

enum class AgentState {
    Idle,
    Parse,
    Decide,
    Execute,
    Hotpatch,
    Validate,
    Complete,
    Failed
};

// ============================================================================
// Orchestrator
// ============================================================================

class AgentOrchestrator {
public:
    AgentOrchestrator();
