private:
    AgentState state_;

    // 7 AI Systems
    SwarmDecisionBridge* swarm_;
    UniversalModelHotpatcher* modelPatch_;
    GPUKernelAutoTuner* gpuTuner_;
    SandboxIntegration* sandbox_;
    ProductionReleaseEngine* release_;
    AMDGPUAccelerator* amdAccel_;
    WebRTCSignaling* webrtc_;

    UnifiedHotpatchManager* hotpatch_;

    // Tool registry (44)
    std::unordered_map<std::string, std::function<AgentResult()>> tools_;

    void registerTools();
    AgentResult executeTool(const std::string& toolName);
};

// ============================================================================
// Constructor
// ============================================================================

AgentOrchestrator::AgentOrchestrator()
    : state_(AgentState::Idle)
{
    swarm_     = SwarmDecisionBridge::instance();
    modelPatch_= UniversalModelHotpatcher::instance();
    gpuTuner_  = GPUKernelAutoTuner::instance();
    sandbox_   = SandboxIntegration::instance();
    release_   = ProductionReleaseEngine::instance();
    amdAccel_  = AMDGPUAccelerator::instance();
    webrtc_    = WebRTCSignaling::instance();
    hotpatch_  = UnifiedHotpatchManager::instance();

    registerTools();
}

// ============================================================================
// State Machine Execution
// ============================================================================

AgentResult AgentOrchestrator::run(const std::string& command)
{
    auto start = std::chrono::high_resolution_clock::now();
    AgentResult result{false, "", "", 0.0};

    state_ = AgentState::Parse;

    try {

        std::string decision;

        while (state_ != AgentState::Complete &&
               state_ != AgentState::Failed)
        {
            switch (state_) {

                case AgentState::Parse:
                    decision = swarm_->decide(command);
                    state_ = AgentState::Decide;
                    break;

                case AgentState::Decide:
                    if (tools_.count(decision)) {
                        state_ = AgentState::Execute;
                    } else {
                        result.message = "Unknown tool";
                        state_ = AgentState::Failed;
                    }
                    break;

                case AgentState::Execute:
                    result = executeTool(decision);
                    state_ = result.success
                        ? AgentState::Hotpatch
                        : AgentState::Failed;
                    break;

                case AgentState::Hotpatch:
                    hotpatch_->pulse();   // Layer 6 dispatch
                    state_ = AgentState::Validate;
                    break;

                case AgentState::Validate:
                    if (hotpatch_->validate()) {
                        state_ = AgentState::Complete;
                    } else {
                        state_ = AgentState::Failed;
                    }
                    break;

                default:
                    state_ = AgentState::Failed;
                    break;
            }
        }

        result.success = (state_ == AgentState::Complete);
    }
    catch (const std::exception& e) {
        result.success = false;
        result.message = e.what();
    }

    auto end = std::chrono::high_resolution_clock::now();
    result.durationMs =
        std::chrono::duration<double, std::milli>(end - start).count();

    return result;
}

// ============================================================================
// Tool Execution
// ============================================================================

AgentResult AgentOrchestrator::executeTool(const std::string& toolName)
{
    return tools_[toolName]();
}

// ============================================================================
// 44 Production Tool Implementations
// ============================================================================

void AgentOrchestrator::registerTools()
{
    // Helper macro
#define TOOL(name, body) \
    tools_[name] = [this]() -> AgentResult { \
        AgentResult r; \
        try { body; r.success = true; r.message = #name " OK"; } \
        catch (...) { r.success = false; r.message = #name " FAIL"; } \
        return r; \
    };

    // 1–7: Core AI Systems
    TOOL("swarm.optimize", swarm_->optimize());
    TOOL("model.patch", modelPatch_->applyGlobalPatch());
    TOOL("gpu.tune", gpuTuner_->runFullTune());
    TOOL("sandbox.enable", sandbox_->enable());
    TOOL("release.build", release_->build());
    TOOL("amd.enable", amdAccel_->enable());
    TOOL("webrtc.init", webrtc_->initialize());

    // 8–14: Hotpatch Ops
    TOOL("hotpatch.memory", hotpatch_->applyMemoryPatch());
    TOOL("hotpatch.byte", hotpatch_->applyBytePatch());
    TOOL("hotpatch.server", hotpatch_->applyServerPatch());
    TOOL("hotpatch.rollback", hotpatch_->rollback());
    TOOL("hotpatch.list", hotpatch_->list());
    TOOL("hotpatch.audit", hotpatch_->audit());
    TOOL("hotpatch.validate", hotpatch_->validate());

    // 15–22: GPU Controls
    TOOL("gpu.enable", amdAccel_->enable());
    TOOL("gpu.disable", amdAccel_->disable());
    TOOL("gpu.memory", amdAccel_->queryMemory());
    TOOL("gpu.features", amdAccel_->queryFeatures());
    TOOL("gpu.reset", amdAccel_->reset());
    TOOL("gpu.telemetry", amdAccel_->telemetry());
    TOOL("gpu.autotune", gpuTuner_->quickTune());
    TOOL("gpu.fulltune", gpuTuner_->runFullTune());

    // 23–30: Model Controls
    TOOL("model.load", modelPatch_->load());
    TOOL("model.unload", modelPatch_->unload());
    TOOL("model.stats", modelPatch_->stats());
    TOOL("model.validate", modelPatch_->validate());
    TOOL("model.repair", modelPatch_->repair());
    TOOL("model.quantize", modelPatch_->quantize());
    TOOL("model.stream", modelPatch_->stream());
    TOOL("model.freeze", modelPatch_->freeze());

    // 31–38: Swarm + Routing
    TOOL("swarm.route", swarm_->route());
    TOOL("swarm.ensemble", swarm_->ensemble());
    TOOL("swarm.pin", swarm_->pin());
    TOOL("swarm.unpin", swarm_->unpin());
    TOOL("swarm.metrics", swarm_->metrics());
    TOOL("swarm.reset", swarm_->reset());
    TOOL("swarm.audit", swarm_->audit());
    TOOL("swarm.health", swarm_->health());

    // 39–44: System Ops
    TOOL("system.health", hotpatch_->systemHealth());
    TOOL("system.snapshot", hotpatch_->snapshot());
    TOOL("system.restore", hotpatch_->restore());
    TOOL("system.stats", hotpatch_->stats());
    TOOL("system.lock", hotpatch_->lock());
    TOOL("system.unlock", hotpatch_->unlock());

#undef TOOL
}

